/**
 * Unit tests for posttool/context-crossing-warn hook.
 *
 * Tracks two zones (windDown 70%, imminent 85% of CLAUDE_MAX_CONTEXT) per
 * session in `.claude/state/session-<id>-token-accum.json`. One-shot fire per
 * zone per session. Cache-aware messaging when cache-read tokens are hot.
 */

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { mockCommonBasic } from '../fixtures/mock-common.js';

vi.mock('node:fs', () => ({
  existsSync: vi.fn(() => false),
  readFileSync: vi.fn(() => '{}'),
  mkdirSync: vi.fn(),
  appendFileSync: vi.fn(),
}));

import { mkdirSync } from 'node:fs';

const { atomicWriteMock } = vi.hoisted(() => ({ atomicWriteMock: vi.fn() }));
vi.mock('../../lib/atomic-write.js', () => ({
  atomicWriteSync: atomicWriteMock,
}));

vi.mock('../../lib/common.js', () => mockCommonBasic());

import { contextCrossingWarn } from '../../posttool/context-crossing-warn.js';
import { existsSync, readFileSync, appendFileSync } from 'node:fs';
import type { HookInput } from '../../types.js';
import { createTestContext } from '../fixtures/test-context.js';

const PROJECT_DIR = '/test/project';

// Pin a small window so threshold math is predictable in tests:
//   200k window → windDown 140k, imminent 170k
const TEST_WINDOW = 200_000;

function makeInput(overrides: Partial<HookInput> = {}): HookInput {
  return {
    tool_name: 'Read',
    session_id: 'sess-A',
    tool_input: {},
    tool_output: 'x'.repeat(4000),
    ...overrides,
  };
}

function lastWrittenState(): {
  estimatedTokens: number;
  crossings: Record<string, boolean>;
  cacheReadTokens: number;
  cacheCreationTokens: number;
} {
  expect(atomicWriteMock).toHaveBeenCalled();
  const lastCall = atomicWriteMock.mock.calls[atomicWriteMock.mock.calls.length - 1];
  return JSON.parse(String(lastCall[1]));
}

const ENV_KEYS = [
  'ORK_NO_CTX_WARN',
  'ORK_CTX_WARN_THRESHOLD',
  'ORK_CTX_WINDDOWN_PCT',
  'ORK_CTX_IMMINENT_PCT',
  'ORK_CACHE_HOT_THRESHOLD',
  'ORK_NO_CACHE_AWARENESS',
  'CLAUDE_MAX_CONTEXT',
];

function clearEnv() {
  for (const k of ENV_KEYS) delete process.env[k];
}

describe('contextCrossingWarn', () => {
  let ctx: ReturnType<typeof createTestContext>;

  beforeEach(() => {
    vi.clearAllMocks();
    atomicWriteMock.mockClear();
    ctx = createTestContext({ projectDir: PROJECT_DIR, sessionId: 'sess-A' });
    clearEnv();
    process.env.CLAUDE_MAX_CONTEXT = String(TEST_WINDOW);
  });

  afterEach(() => clearEnv());

  describe('zone semantics (#1480) — windDown then imminent', () => {
    it('stays silent below windDown (< 70% of window)', () => {
      vi.mocked(existsSync).mockReturnValue(false);
      const result = contextCrossingWarn(makeInput({ tool_output: 'small' }), ctx);
      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
      expect(result.hookSpecificOutput?.additionalContext).toBeUndefined();
    });

    it('fires soft windDown notice when crossing 70% (140k tokens at 200k window)', () => {
      vi.mocked(existsSync).mockReturnValue(true);
      vi.mocked(readFileSync).mockReturnValue(
        JSON.stringify({
          estimatedTokens: 139_500,
          cacheReadTokens: 0,
          cacheCreationTokens: 0,
          crossings: {},
          firstSeenAt: new Date(Date.now() - 60_000).toISOString(),
          updatedAt: new Date(Date.now() - 60_000).toISOString(),
        }),
      );
      // 4000 chars ≈ 1000 tokens → 140,500 (over windDown 140k)
      const result = contextCrossingWarn(makeInput(), ctx);
      const msg = result.hookSpecificOutput?.additionalContext;
      expect(msg).toBeDefined();
      expect(msg).toContain('Approaching compact');
      expect(msg).toMatch(/~\d+%/);
      expect(lastWrittenState().crossings['windDown:140000']).toBe(true);
      expect(lastWrittenState().crossings['imminent:170000']).toBeUndefined();
    });

    it('fires hard imminent notice when crossing 85% (170k tokens at 200k window)', () => {
      vi.mocked(existsSync).mockReturnValue(true);
      vi.mocked(readFileSync).mockReturnValue(
        JSON.stringify({
          estimatedTokens: 169_500,
          cacheReadTokens: 0,
          cacheCreationTokens: 0,
          crossings: { 'windDown:140000': true },
          firstSeenAt: new Date(Date.now() - 60_000).toISOString(),
          updatedAt: new Date(Date.now() - 60_000).toISOString(),
        }),
      );
      const result = contextCrossingWarn(makeInput(), ctx);
      const msg = result.hookSpecificOutput?.additionalContext;
      expect(msg).toBeDefined();
      expect(msg).toContain('Session context crossed');
      expect(msg).toContain('/clear');
      expect(msg).toContain('/compact');
      expect(lastWrittenState().crossings['imminent:170000']).toBe(true);
    });

    it('fires imminent (not windDown) when single tool result jumps both', () => {
      vi.mocked(existsSync).mockReturnValue(false);
      // 720k chars at prose ÷ 4 = 180k tokens — overshoots both thresholds
      const result = contextCrossingWarn(
        makeInput({ tool_output: 'x'.repeat(720_000) }),
        ctx,
      );
      const msg = result.hookSpecificOutput?.additionalContext;
      expect(msg).toContain('Session context crossed');
      const state = lastWrittenState();
      expect(state.crossings['imminent:170000']).toBe(true);
      // windDown also marked so we don't backward-fire the soft notice later
      expect(state.crossings['windDown:140000']).toBe(true);
    });

    it('does not double-fire imminent on next call in same session', () => {
      vi.mocked(existsSync).mockReturnValue(true);
      vi.mocked(readFileSync).mockReturnValue(
        JSON.stringify({
          estimatedTokens: 175_000,
          cacheReadTokens: 0,
          cacheCreationTokens: 0,
          crossings: { 'windDown:140000': true, 'imminent:170000': true },
          firstSeenAt: new Date(Date.now() - 60_000).toISOString(),
          updatedAt: new Date(Date.now() - 60_000).toISOString(),
        }),
      );
      const result = contextCrossingWarn(makeInput(), ctx);
      expect(result.suppressOutput).toBe(true);
      expect(result.hookSpecificOutput?.additionalContext).toBeUndefined();
    });
  });

  describe('back-compat env override (#1475)', () => {
    it('honours ORK_CTX_WARN_THRESHOLD as raw imminent threshold (no windDown)', () => {
      process.env.ORK_CTX_WARN_THRESHOLD = '5000';
      vi.mocked(existsSync).mockReturnValue(false);

      const result = contextCrossingWarn(
        makeInput({ tool_output: 'z'.repeat(20_000) }),
        ctx,
      );
      expect(result.hookSpecificOutput?.additionalContext).toContain('5,000');
      expect(lastWrittenState().crossings['5000']).toBe(true);
    });

    it('falls back to default zones when ORK_CTX_WARN_THRESHOLD is invalid', () => {
      process.env.ORK_CTX_WARN_THRESHOLD = 'not-a-number';
      vi.mocked(existsSync).mockReturnValue(false);
      const result = contextCrossingWarn(
        makeInput({ tool_output: 'x'.repeat(4000) }),
        ctx,
      );
      // 1000 tokens — well under 140k windDown — silent
      expect(result.suppressOutput).toBe(true);
    });
  });

  describe('window scaling (#1475)', () => {
    it('scales thresholds at 1M context window', () => {
      process.env.CLAUDE_MAX_CONTEXT = '1000000';
      vi.mocked(existsSync).mockReturnValue(false);
      // 600k tokens needed to even hit windDown at 1M
      const result = contextCrossingWarn(
        makeInput({ tool_output: 'x'.repeat(2_400_000) }),
        ctx,
      );
      // 600k tokens crosses windDown=700k? No: 600k < 700k → silent
      expect(result.suppressOutput).toBe(true);
    });

    it('fires windDown around 700k at 1M context window', () => {
      process.env.CLAUDE_MAX_CONTEXT = '1000000';
      vi.mocked(existsSync).mockReturnValue(true);
      vi.mocked(readFileSync).mockReturnValue(
        JSON.stringify({
          estimatedTokens: 699_500,
          cacheReadTokens: 0,
          cacheCreationTokens: 0,
          crossings: {},
          firstSeenAt: new Date(Date.now() - 60_000).toISOString(),
          updatedAt: new Date(Date.now() - 60_000).toISOString(),
        }),
      );
      const result = contextCrossingWarn(makeInput(), ctx);
      expect(result.hookSpecificOutput?.additionalContext).toContain('Approaching');
      expect(lastWrittenState().crossings['windDown:700000']).toBe(true);
    });
  });

  describe('cache-aware messaging (#1479)', () => {
    it('imminent message recommends /compact when cache is hot', () => {
      vi.mocked(existsSync).mockReturnValue(true);
      vi.mocked(readFileSync).mockReturnValue(
        JSON.stringify({
          estimatedTokens: 169_500,
          cacheReadTokens: 80_000, // > default ORK_CACHE_HOT_THRESHOLD (50k)
          cacheCreationTokens: 20_000,
          crossings: { 'windDown:140000': true },
          firstSeenAt: new Date(Date.now() - 60 * 60 * 1000).toISOString(), // > 30 min ago
          updatedAt: new Date(Date.now() - 60_000).toISOString(),
        }),
      );
      const result = contextCrossingWarn(makeInput(), ctx);
      const msg = result.hookSpecificOutput?.additionalContext;
      expect(msg).toContain('warm cache');
      expect(msg).toContain('Consider /compact');
      expect(msg).toContain('80,000');
    });

    it('imminent message stays neutral on short session (< 30 min)', () => {
      vi.mocked(existsSync).mockReturnValue(true);
      vi.mocked(readFileSync).mockReturnValue(
        JSON.stringify({
          estimatedTokens: 169_500,
          cacheReadTokens: 80_000,
          cacheCreationTokens: 20_000,
          crossings: { 'windDown:140000': true },
          firstSeenAt: new Date(Date.now() - 5 * 60_000).toISOString(),
          updatedAt: new Date(Date.now() - 60_000).toISOString(),
        }),
      );
      const result = contextCrossingWarn(makeInput(), ctx);
      const msg = result.hookSpecificOutput?.additionalContext;
      expect(msg).not.toContain('warm cache');
      expect(msg).toContain('/clear');
    });

    it('ORK_NO_CACHE_AWARENESS=1 forces neutral messaging even when hot', () => {
      process.env.ORK_NO_CACHE_AWARENESS = '1';
      vi.mocked(existsSync).mockReturnValue(true);
      vi.mocked(readFileSync).mockReturnValue(
        JSON.stringify({
          estimatedTokens: 169_500,
          cacheReadTokens: 200_000,
          cacheCreationTokens: 50_000,
          crossings: { 'windDown:140000': true },
          firstSeenAt: new Date(Date.now() - 60 * 60 * 1000).toISOString(),
          updatedAt: new Date(Date.now() - 60_000).toISOString(),
        }),
      );
      const result = contextCrossingWarn(makeInput(), ctx);
      const msg = result.hookSpecificOutput?.additionalContext;
      expect(msg).not.toContain('warm cache');
    });
  });

  describe('opt-out', () => {
    it('is fully silent when ORK_NO_CTX_WARN=1', () => {
      process.env.ORK_NO_CTX_WARN = '1';
      const result = contextCrossingWarn(
        makeInput({ tool_output: 'x'.repeat(1_000_000) }),
        ctx,
      );
      expect(result.suppressOutput).toBe(true);
      expect(atomicWriteMock).not.toHaveBeenCalled();
    });
  });

  describe('input shape handling', () => {
    it('image payload is not counted toward token accumulator', () => {
      vi.mocked(existsSync).mockReturnValue(false);
      const imgPayload = `data:image/png;base64,${'x'.repeat(100_000)}`;
      contextCrossingWarn(
        { tool_name: 'Read', session_id: 'img', tool_input: {}, tool_result: imgPayload } as HookInput,
        createTestContext({ projectDir: PROJECT_DIR, sessionId: 'img' }),
      );
      const state = JSON.parse(String(atomicWriteMock.mock.calls[0][1]));
      expect(state.estimatedTokens).toBe(0);
      expect(state.imageResponses).toBe(1);
    });

    it('image payload writes to telemetry log', () => {
      vi.mocked(existsSync).mockReturnValue(false);
      vi.mocked(appendFileSync).mockClear();
      contextCrossingWarn(
        {
          tool_name: 'Agent',
          session_id: 'img2',
          tool_input: {},
          tool_result: `data:image/jpeg;base64,/9j/4AAQSkZJ${'x'.repeat(500)}`,
        } as HookInput,
        createTestContext({ projectDir: PROJECT_DIR, sessionId: 'img2' }),
      );
      expect(appendFileSync).toHaveBeenCalled();
      const [logPath] = vi.mocked(appendFileSync).mock.calls[0];
      expect(String(logPath)).toContain('image-responses.jsonl');
    });

    it('handles corrupt state file gracefully and resets accumulator', () => {
      vi.mocked(existsSync).mockReturnValue(true);
      vi.mocked(readFileSync).mockReturnValue('not valid json');
      const result = contextCrossingWarn(makeInput(), ctx);
      expect(result.continue).toBe(true);
      expect(lastWrittenState().estimatedTokens).toBeGreaterThan(0);
    });
  });

  describe('write-fail graceful degradation', () => {
    it('returns silent success when mkdir throws', () => {
      vi.mocked(existsSync).mockReturnValue(false);
      vi.mocked(mkdirSync).mockImplementationOnce(() => {
        throw new Error('ENOSPC: no space left on device');
      });
      const result = contextCrossingWarn(makeInput(), ctx);
      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
    });

    it('returns silent success when atomicWrite throws', () => {
      vi.mocked(existsSync).mockReturnValue(false);
      atomicWriteMock.mockImplementationOnce(() => {
        throw new Error('EACCES: permission denied');
      });
      const result = contextCrossingWarn(makeInput(), ctx);
      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
    });
  });
});
